import { Component, OnInit } from '@angular/core';
import { MagicService } from '../../services/magic.service';
import { Magic } from '../../models/magic';
import { Router } from '@angular/router';


@Component({
  selector: 'app-magias',
  templateUrl: './magias.component.html',
  styleUrls: ['./magias.component.css']
})
export class MagiasComponent implements OnInit{

  magias!: { count: number, results: Magic[] };
  loading: boolean = true;
  error: string = '';

   // Filtros
   filters = {
    level: '',
    school: '',
    class: '',
    name: ''
  };

  niveis = [
    { value: '', label: 'Todos os níveis' },
    { value: '1', label: 'Nível 1' },
    { value: '2', label: 'Nível 2' },
    { value: '3', label: 'Nível 3' },
    { value: '4', label: 'Nível 4' },
    { value: '5', label: 'Nível 5' },
    { value: '6', label: 'Nível 6' },
    { value: '7', label: 'Nível 7' },
    { value: '8', label: 'Nível 8' },
    { value: '9', label: 'Nível 9' }
  ];

  classes = ['Mago', 'Feiticeiro', 'Druida', 'Clérigo', 'Paladino', 'Patrulheiro', 'Bardo', 'Bruxo'];

  escolas = ['Evocação', 'Conjuração', 'Necromancia', 'Transmutação', 'Adivinhação', 'Encantamento', 'Ilusão', 'Abjuração']; 


  constructor(private magicService: MagicService,
              private router: Router) {}

              ngOnInit(): void {
                this.loadMagics();
                this.fetchMagics();

              //  this.magicService.getMagics().subscribe({
              //    next: (data) => {
               //     this.magias = data;
                //    this.loading = false;
               //   },
               //   error: (err) => {
               //     this.error = 'Erro ao carregar as magias.';
               //     this.loading = false;
               //   }
              //  });
              }

              onFilterChange(): void {
                this.fetchMagics();  // Recarrega as magias sempre que algum filtro for alterado
              }

              fetchMagics(): void {
                this.loading = true;
                this.magicService.getMagicsByFilter(this.filters).subscribe({
                  next: (data) => {
                    this.magias = data;
                    this.loading = false;
                  },
                  error: (err) => {
                    this.error = 'Erro ao carregar as magias.';
                    this.loading = false;
                  }
                });
              }

              loadMagics(): void {
                this.loading = true;
                this.magicService.getMagics().subscribe({
                  next: (data) => {
                    this.magias = data;
                    this.loading = false;
                  },
                  error: (err) => {
                    this.error = 'Erro ao carregar as magias.';
                    this.loading = false;
                  }
                });
              }
              applyFilters(): void {
    this.loading = true;

    const level = this.filters.level ? parseInt(this.filters.level, 10) : undefined;
    const { school, class: className } = this.filters;

    // Verifica se algum filtro foi preenchido
    if (!level && !school && !className) {
        // Se nenhum filtro foi aplicado, pega todas as magias
        this.magicService.getMagics().subscribe({
            next: (data) => {
                this.magias = data;
                this.error = ''; // Limpa qualquer mensagem de erro
                this.loading = false;
            },
            error: (err) => {
                this.error = 'Erro ao carregar as magias.';
                this.loading = false;
            }
        });
    } else {
        // Se algum filtro foi preenchido, aplica o filtro
        this.magicService.getFilteredMagics(level, school, className).subscribe({
            next: (data) => {
                if (data.count === 0) {
                    this.magias = { count: 0, results: [] };
                    this.error = 'Nenhuma magia encontrada com os filtros aplicados.';
                } else {
                    this.magias = data;
                    this.error = ''; // Limpa qualquer mensagem de erro
                }
                this.loading = false;
            },
            error: (err) => {
                this.error = 'Erro ao carregar as magias com os filtros aplicados.';
                this.loading = false;
            }
        });
    }
}

              goToDetail(index: string): void {
                this.router.navigate(['/magias', index]);
              }


}
